                pq.insert(dp2[i][j]+dp1[i][j-1]);
            }
        }

        for(int i=0;i<n;i++){
            if(j-1>=0){
                pq.erase(pq.find(dp2[i][j]+dp1[i][j-1]));
            }
            int curr;
            if(i==0 && j==0){
                curr=dp2[i][j];
            }else{
                curr=min(i>=1?dp1[i-1][j]:-INF,j>=1?dp1[i][j-1]:-INF)+dp2[i][j];
            }
            curr-=2*arr[i][j];
            ans=min({ans,max(*pq.rbegin(),curr)});
            if(j+1<m){
                pq.insert(dp1[i][j]+dp2[i][j+1]);
            }
        }
    }
    cout<<ans<<endl;
}

