    int n,m;
    cin>>n>>m;

    vvi dp1(n,vi(m,0));

    vvi arr(n,vi(m,0));
    vvi dp2=dp1;
    for(int i=0;i<n;i++){
        for(int j=0;j<m;j++){
            cin>>arr[i][j];
        }
    }

    for(int i=0;i<n;i++){
        for(int j=0;j<m;j++){
            if(i==0 && j==0){
                dp1[i][j]=arr[i][j];continue;
            } 
            dp1[i][j]=max(i>=1?dp1[i-1][j]:-INF,j>=1?dp1[i][j-1]:-INF)+arr[i][j];
        }
    }

    for(int i=n-1;i>=0;i--){
        for(int j=m-1;j>=0;j--){
            if(i==n-1 && j==m-1){
                dp2[i][j]=arr[i][j];
                continue;
            }
            dp2[i][j]=max((i+1)<n?dp2[i+1][j]:-INF,(j+1)<m?dp2[i][j+1]:-INF)+arr[i][j];
        }
    }

    int ans=INF;

    for(int j=0;j<m;j++){
        multiset<int> pq;
        pq.insert(-INF);
        for(int i=0;i<n;i++){
            if(j-1>=0){
                pq.insert(dp2[i][j]+dp1[i][j-1]);
            }
        }

        for(int i=0;i<n;i++){
            if(j-1>=0){
                pq.erase(pq.find(dp2[i][j]+dp1[i][j-1]));
            }
            int curr;
            if(i==0 && j==0){
                curr=dp2[i][j];
            }else{
                curr=max(i>=1?dp1[i-1][j]:-INF,j>=1?dp1[i][j-1]:-INF)+dp2[i][j];
            }
            curr-=2*arr[i][j];
            ans=min({ans,max(*pq.rbegin(),curr)});
            if(j+1<m){
                pq.insert(dp1[i][j]+dp2[i][j+1]);
            }
        }
    }
    cout<<ans<<"\n";
}

void precomp();

int totalTestCase=1;

int32_t main(){
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    std::cout << std::fixed << std::setprecision(15);
    precomp();
    if(haveTestCase){
        cin>>totalTestCase;
    }
    for(int i=1;i<=totalTestCase;i++){
        solve(i);
    }
    return 0;
}

void precomp(){
    if (sieveSize >= 2){ 
        for (int i = 2; i * i < sieveSize; i++){
            if (sieve[i] == 0){
                for (int j = i * i; j < sieveSize; j += i){
                    if(sieve[j]==0)
                        sieve[j] = i;
                }
            }
        }
    }
    if(combSize>2){
        modinv[0]=1;
        fact[0]=1;
        for(int i=1;i<combSize;i++){
            fact[i]=(fact[i-1]*i)%MOD;
            modinv[i]=fexpo(fact[i],MOD-2);
        }
    }
};
